import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum addressTypes {
  POST_REQUEST = '@addressTypes/POST_REQUEST',
  POST_SUCCESS = '@addressTypes/POST_SUCCESS',
  POST_FAILED = '@addressTypes/POST_FAILED',
  CLEAR = '@addressTypes/CLEAN',
}

export interface AddressData {
  typeAddress: string;
  zipCode: string;
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  state: string;
  complement: string;
  reference: string;
}


export interface UpdateAddressResponse {
  data: unknown;
  status: {
    codigoRetorno: number;
    mensagem: string;
  };
  error?: boolean;
  description: string;
  salvarResponse?: unknown;
}
export interface AddressReducerProps {
  isLoading: boolean;
  isError: boolean;
  address?: AddressData;
  addressReserved?: AddressData;
}

export const initialState: AddressReducerProps = {
  isLoading: false,
  isError: false,
  address: undefined,
  addressReserved: undefined,
};

export const AddressReducer = createReducer(initialState, {
  [addressTypes.POST_REQUEST](state: AddressReducerProps) {
    return {
      ...state,
      isLoading: true,
      isError: false,
    };
  },
  [addressTypes.POST_SUCCESS](
    state: AddressReducerProps,
    { address }: { address: AddressData },
  ) {
    return {
      ...state,
      address,
      isLoading: false,
      isError: false,
      addressReserved: undefined,
    };
  },
  [addressTypes.ADDRESS_RESERVED_SUCCESS](
    state: AddressReducerProps,
    { address }: { address: AddressData },
  ) {
    return {
      ...state,
      addressReserved: address,
    };
  },
  [addressTypes.POST_FAILED](state: AddressReducerProps) {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [addressTypes.CLEAR]() {
    return {
      isLoading: false,
      isError: false,
      address: undefined,
    };
  },
});

export interface AddressActions {
  postRequest: (addressData: AddressData, callback: AddressCallback) => Action;
  postSuccess: (address: AddressData) => Action;
  postFailed: () => Action;
  clearAddress: () => Action;
  addressReservedSuccess: (address: AddressData) => Action;
}

export const AddressActions: AddressActions = {
  postRequest: (addressData: AddressData, callback: AddressCallback) => ({
    type: addressTypes.POST_REQUEST,
    addressData,
    callback,
  }),
  postSuccess: (address: AddressData) => ({
    type: addressTypes.POST_SUCCESS,
    address,
  }),
  postFailed: () => ({
    type: addressTypes.POST_FAILED,
  }),
  clearAddress: () => ({
    type: addressTypes.CLEAR,
  }),
  addressReservedSuccess: (address: AddressData) => ({
    type: addressTypes.ADDRESS_RESERVED_SUCCESS,
    address,
  }),
};

