import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum CreatePasswordTypes {
  REQUEST = '@createPassword/CREATE_PASSWORD_REQUEST',
  SUCCESS = '@createPassword/CREATE_PASSWORD_SUCCESS',
  FAILED = '@createPassword/CREATE_PASSWORD_FAILED',
}

export interface CreatePasswordProps {
  isLoading: boolean;
  isError: boolean;
  isSuccessful: boolean;
}

type State = CreatePasswordProps;

const initialState: CreatePasswordProps = {
  isLoading: false,
  isError: false,
  isSuccessful: false,
};

const createPasswordReducer = createReducer(initialState, {
  [CreatePasswordTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [CreatePasswordTypes.SUCCESS](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
    };
  },
  [CreatePasswordTypes.FAILED](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [CreatePasswordTypes.CLEAR](): State {
    return initialState;
  },
});

type CreatePasswordActions = {
  createPasswordRequest: (data: {
    lastFourNumbers: string;
    password: string;
  }) => Action;
  createPasswordSuccess: () => Action;
  createPasswordFailed: () => Action;
};

export const createPasswordActions: CreatePasswordActions = {
  createPasswordRequest: (data, callback) => ({
    type: CreatePasswordTypes.REQUEST,
    data,
    callback,
  }),
  createPasswordSuccess: () => ({
    type: CreatePasswordTypes.SUCCESS,
  }),
  createPasswordFailed: () => ({
    type: CreatePasswordTypes.FAILED,
  }),
  createPasswordClear: () => ({
    type: CreatePasswordTypes.CLEAR,
  }),
};

export default createPasswordReducer;

